exercises.solution_code:
#include <iostream>
#include <iomanip>
#include <string>

class TemperatureSensor {
public:
    void setReading(double value) {
        m_reading = value;
    }

    double getReading() const {
        return m_reading;
    }

private:
    double m_reading{0.0};
};

int main() {
    TemperatureSensor sensor{};

    int n{};
    std::cin >> n;

    std::cout << std::fixed << std::setprecision(2);

    for (int i{0}; i < n; ++i) {
        std::string command{};
        std::cin >> command;

        if (command == "set") {
            double value{};
            std::cin >> value;
            sensor.setReading(value);
        } else if (command == "get") {
            std::cout << "Reading: " << sensor.getReading() << '\n';
        }
    }

    return 0;
}

