exercises.solution_code:
#include <iostream>
#include <string>

class Counter {
public:
    void increment() {
        ++m_count;
    }

    void decrement() {
        if (m_count > 0)
            --m_count;
    }

    void reset() {
        m_count = 0;
    }

    int getCount() const {
        return m_count;
    }

private:
    int m_count{0};
};

int main() {
    Counter counter{};

    int n{};
    std::cin >> n;

    for (int i{0}; i < n; ++i) {
        std::string command{};
        std::cin >> command;

        if (command == "increment") {
            counter.increment();
        } else if (command == "decrement") {
            counter.decrement();
        } else if (command == "reset") {
            counter.reset();
        } else if (command == "print") {
            std::cout << "Count: " << counter.getCount() << '\n';
        }
    }

    return 0;
}
